import 'package:flutter/material.dart';void main() => runApp(const MyApp());class MyApp extends StatelessWidget {  const MyApp({super.key});  @override  Widget build(BuildContext context) {    return const MaterialApp(      home: DemoPage(),    );  }}class DemoPage extends StatelessWidget {  const DemoPage({super.key});  @override  Widget build(BuildContext context) {    return Scaffold(      appBar: AppBar(title: const Text("Semantics Demo")),      body: Column(        mainAxisAlignment: MainAxisAlignment.center,        children: [          /// ❌ WITHOUT Semantics          const Text("Without Semantics"),          IconButton(            onPressed: () {},            icon: const Icon(Icons.login),          ),          const SizedBox(height: 40),          /// ✅ WITH Semantics          const Text("With Semantics"),          Semantics(            label: "Login Button",            button: true,            child: IconButton(              onPressed: () {},              icon: const Icon(Icons.login),            ),          ),        ],      ),    );  }}